// app/dashboard/analytics/page.tsx - Fixed version
'use client'

import { useState, useEffect } from 'react'
import { supabase } from '../../../lib/supabase'
import { Header } from '../../../components/layout/Header'
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, 
  PieChart, Pie, Cell, LineChart, Line, ResponsiveContainer 
} from 'recharts'
import { FiUsers, FiMap, FiNavigation, FiBell, FiTrendingUp, FiSearch, FiMapPin, FiCalendar, FiClock } from 'react-icons/fi'

const COLORS = ['#6b21a8', '#8b5cf6', '#10B981', '#EF4444', '#F59E0B', '#3B82F6', '#EC4899', '#8B5D34']

// Common Ghanaian regions for reference
const GHANA_REGIONS = [
  'Greater Accra', 'Ashanti', 'Western', 'Central', 'Eastern', 
  'Volta', 'Northern', 'Upper East', 'Upper West', 'Brong Ahafo',
  'Oti', 'North East', 'Savannah', 'Bono', 'Bono East', 'Ahafo'
]

export default function AnalyticsPage() {
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalRoutes: 0,
    totalStops: 0,
    activeUsers: 0,
    notificationsSent: 0,
    totalSearches: 0,
    userCreatedRoutes: 0,
    totalPayments: 0
  })
  
  const [userGrowth, setUserGrowth] = useState<any[]>([])
  const [routeData, setRouteData] = useState<any[]>([])
  const [notificationData, setNotificationData] = useState<any[]>([])
  const [popularSearches, setPopularSearches] = useState<any[]>([])
  const [topRegions, setTopRegions] = useState<any[]>([])
  const [activeHoursData, setActiveHoursData] = useState<any[]>([])
  const [userDistributionByHour, setUserDistributionByHour] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetchAnalyticsData()
  }, [])

  const fetchAnalyticsData = async () => {
    try {
      setLoading(true)
      
      // Fetch all data in parallel
      const [
        { data: users, error: usersError },
        { data: profiles, error: profilesError },
        { data: routes, error: routesError },
        { data: stops, error: stopsError },
        { data: notifications, error: notificationsError },
        { data: searchHistory, error: searchHistoryError },
        { data: userCreatedRoutes, error: userCreatedRoutesError },
        { data: payments, error: paymentsError }
      ] = await Promise.all([
        supabase.from('users').select('*, created_at'),
        supabase.from('profiles').select('*, last_location, last_seen_at'),
        supabase.from('routes').select('*'),
        supabase.from('stops').select('*'),
        supabase.from('notifications').select('*'),
        supabase.from('search_history').select('*'),
        supabase.from('user_created_routes').select('*'),
        supabase.from('route_creation_payments').select('*')
      ])

      if (usersError) console.error('Users error:', usersError)
      if (profilesError) console.error('Profiles error:', profilesError)
      if (routesError) console.error('Routes error:', routesError)
      if (stopsError) console.error('Stops error:', stopsError)
      if (notificationsError) console.error('Notifications error:', notificationsError)
      if (searchHistoryError) console.error('Search history error:', searchHistoryError)
      if (userCreatedRoutesError) console.error('User created routes error:', userCreatedRoutesError)
      if (paymentsError) console.error('Payments error:', paymentsError)

      // Process user growth data
      const growthData = processUserGrowth(users || [])
      
      // Get route statistics
      const routeStats = getRouteStats(routes || [])
      
      // Get notification statistics
      const notificationStats = getNotificationStats(notifications || [])
      
      // Get popular searches
      const popularSearchesData = getPopularSearches(searchHistory || [])
      
      // Get top regions from user locations in profiles
      const topRegionsData = getUserRegionsFromProfiles(profiles || [])
      
      // Get active hours from search history
      const hoursData = getActiveHours(searchHistory || [])
      
      // Get user distribution by hour of day from last_seen_at
      const userDistributionData = getUserDistributionByHour(profiles || [])

      setStats({
        totalUsers: (users || []).length,
        totalRoutes: (routes || []).length,
        totalStops: (stops || []).length,
        activeUsers: getActiveUsers(profiles || []),
        notificationsSent: (notifications || []).reduce((sum, n) => sum + (n.sent_count || 0), 0),
        totalSearches: (searchHistory || []).length,
        userCreatedRoutes: (userCreatedRoutes || []).length,
        totalPayments: (payments || []).reduce((sum, p) => sum + (p.amount || 0), 0)
      })

      setUserGrowth(growthData)
      setRouteData(routeStats)
      setNotificationData(notificationStats)
      setPopularSearches(popularSearchesData)
      setTopRegions(topRegionsData) // Now this is just an array
      setActiveHoursData(hoursData)
      setUserDistributionByHour(userDistributionData)
      
    } catch (error) {
      console.error('Failed to fetch analytics:', error)
    } finally {
      setLoading(false)
    }
  }

  const getActiveUsers = (profiles: any[]) => {
    const now = new Date()
    const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000)
    
    return profiles.filter(profile => {
      if (!profile.last_seen_at) return false
      const lastSeen = new Date(profile.last_seen_at)
      return lastSeen > oneDayAgo
    }).length
  }

  const processUserGrowth = (users: any[]) => {
    const now = new Date()
    const last12Months = Array.from({ length: 12 }, (_, i) => {
      const date = new Date(now.getFullYear(), now.getMonth() - i, 1)
      return {
        month: date.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }),
        users: 0,
        fullDate: date,
        cumulative: 0
      }
    }).reverse()

    // Sort users by creation date
    const sortedUsers = [...users].sort((a, b) => 
      new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
    )

    // Calculate cumulative users and monthly additions
    let cumulative = 0
    last12Months.forEach(monthData => {
      const monthStart = monthData.fullDate
      const monthEnd = new Date(monthStart.getFullYear(), monthStart.getMonth() + 1, 0)
      
      const newUsers = sortedUsers.filter(user => {
        if (!user.created_at) return false
        const created = new Date(user.created_at)
        return created >= monthStart && created <= monthEnd
      }).length
      
      cumulative += newUsers
      monthData.users = newUsers
      monthData.cumulative = cumulative
    })

    // Remove the date property for chart
    return last12Months.map(({ fullDate, ...rest }) => rest)
  }

  const getRouteStats = (routes: any[]) => {
    // Group by vehicle type
    const stats = routes.reduce((acc: any, route) => {
      const type = route.vehicle_type || 'Unknown'
      if (!acc[type]) {
        acc[type] = { approved: 0, pending: 0, total: 0 }
      }
      acc[type].total++
      if (route.approved) {
        acc[type].approved++
      } else {
        acc[type].pending++
      }
      return acc
    }, {})

    return Object.entries(stats).map(([type, data]: any) => ({
      type,
      approved: data.approved,
      pending: data.pending,
      total: data.total,
      approvalRate: data.total > 0 ? Math.round((data.approved / data.total) * 100) : 0
    }))
  }

  const getNotificationStats = (notifications: any[]) => {
    const typeStats = notifications.reduce((acc: any, notification) => {
      const type = notification.type || 'unknown'
      if (!acc[type]) {
        acc[type] = {
          count: 0,
          totalSent: 0,
          totalRead: 0
        }
      }
      acc[type].count++
      acc[type].totalSent += notification.sent_count || 0
      acc[type].totalRead += notification.read_count || 0
      return acc
    }, {})

    return Object.entries(typeStats).map(([type, data]: any) => ({
      type: type.charAt(0).toUpperCase() + type.slice(1),
      count: data.count,
      sent: data.totalSent,
      read: data.totalRead,
      readRate: data.totalSent > 0 ? (data.totalRead / data.totalSent) * 100 : 0
    }))
  }

  const getPopularSearches = (searches: any[]) => {
    // Group search combinations
    const searchCounts: Record<string, number> = {}
    
    searches.forEach(search => {
      if (!search.start_point || !search.destination) return
      const key = `${search.start_point.trim()} → ${search.destination.trim()}`
      searchCounts[key] = (searchCounts[key] || 0) + 1
    })

    // Convert to array and sort
    return Object.entries(searchCounts)
      .map(([name, count]) => ({ 
        name, 
        count,
        popularity: count > 10 ? 'High' : count > 5 ? 'Medium' : 'Low'
      }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 15)
  }

  const getUserRegionsFromProfiles = (profiles: any[]): any[] => {
    const regionCounts: Record<string, number> = {}
    let totalUsersWithLocation = 0
    
    profiles.forEach(profile => {
      if (profile.last_location && typeof profile.last_location === 'object') {
        // Check if region exists in last_location object
        if (profile.last_location.region) {
          const region = profile.last_location.region
          // Try to match with known Ghanaian regions
          const matchedRegion = matchGhanaRegion(region)
          regionCounts[matchedRegion] = (regionCounts[matchedRegion] || 0) + 1
          totalUsersWithLocation++
        }
      }
    })

    // Convert to array and sort
    return Object.entries(regionCounts)
      .map(([name, count]) => ({ 
        name, 
        count,
        percentage: totalUsersWithLocation > 0 ? (count / totalUsersWithLocation) * 100 : 0
      }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 10)
  }

  // Helper function to match location text to Ghanaian regions
  const matchGhanaRegion = (locationText: string): string => {
    if (!locationText) return 'Unknown'
    
    const text = locationText.toLowerCase()
    
    // Check for common region names
    if (text.includes('accra')) return 'Greater Accra'
    if (text.includes('kumasi')) return 'Ashanti'
    if (text.includes('tamale')) return 'Northern'
    if (text.includes('takoradi') || text.includes('sekondi')) return 'Western'
    if (text.includes('cape coast')) return 'Central'
    if (text.includes('koforidua')) return 'Eastern'
    if (text.includes('ho')) return 'Volta'
    if (text.includes('sunyani')) return 'Bono'
    if (text.includes('wa')) return 'Upper West'
    if (text.includes('bolgatanga')) return 'Upper East'
    
    // Check for region names in the text
    for (const region of GHANA_REGIONS) {
      if (text.includes(region.toLowerCase())) {
        return region
      }
    }
    
    // If no match found, return the original text (capitalized)
    return locationText.charAt(0).toUpperCase() + locationText.slice(1).toLowerCase()
  }

  const getActiveHours = (searches: any[]) => {
    const hourCounts = Array(24).fill(0)
    
    searches.forEach(search => {
      if (search.searched_at) {
        const date = new Date(search.searched_at)
        const hour = date.getHours()
        hourCounts[hour]++
      }
    })

    // Format for chart
    return hourCounts.map((count, hour) => ({
      hour: `${hour}:00`,
      hour24: hour,
      count,
      period: hour < 12 ? 'AM' : 'PM',
      formattedHour: `${hour % 12 || 12}${hour < 12 ? 'AM' : 'PM'}`
    }))
  }

  const getUserDistributionByHour = (profiles: any[]) => {
    const hourCounts = Array(24).fill(0)
    
    profiles.forEach(profile => {
      if (profile.last_seen_at) {
        try {
          const date = new Date(profile.last_seen_at)
          const hour = date.getHours()
          hourCounts[hour]++
        } catch (error) {
          console.error('Error parsing date:', profile.last_seen_at)
        }
      }
    })

    // Format for chart
    return hourCounts.map((count, hour) => ({
      hour: `${hour}:00`,
      hour24: hour,
      users: count,
      period: hour < 12 ? 'AM' : 'PM',
      formattedHour: `${hour % 12 || 12}${hour < 12 ? 'AM' : 'PM'}`
    }))
  }

  // Calculate region summary stats
  const getRegionSummary = () => {
    if (topRegions.length === 0) {
      return {
        totalUsers: stats.totalUsers,
        usersWithLocation: 0,
        locationPercentage: 0,
        totalRegions: 0
      }
    }

    const usersWithLocation = topRegions.reduce((sum, region) => sum + region.count, 0)
    
    return {
      totalUsers: stats.totalUsers,
      usersWithLocation,
      locationPercentage: stats.totalUsers > 0 ? (usersWithLocation / stats.totalUsers) * 100 : 0,
      totalRegions: topRegions.length
    }
  }

  if (loading) {
    return (
      <div className="space-y-6">
        <Header 
          title="Analytics Dashboard" 
          subtitle="Comprehensive analytics and insights for Ghana Trotro Transit"
        />
        <div className="text-center py-12">
          <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
          <p className="mt-4 text-text">Loading analytics data...</p>
        </div>
      </div>
    )
  }

  const regionSummary = getRegionSummary()

  return (
    <div className="space-y-6">
      <Header 
        title="Analytics Dashboard" 
        subtitle="Comprehensive analytics and insights for Ghana Trotro Transit"
      />

      {/* Stats Cards - Same as before */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-8 gap-4">
        {/* ... (All 8 stat cards remain exactly the same) ... */}
        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Total Users</p>
              <p className="text-2xl font-bold text-text">{stats.totalUsers.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-blue-100 rounded-lg">
              <FiUsers className="text-blue-600" size={20} />
            </div>
          </div>
          <div className="mt-2">
            <div className="flex items-center text-green-600 text-xs">
              <FiTrendingUp className="mr-1" />
              <span>
                {userGrowth.length > 1 && userGrowth[0]?.users > 0 ? 
                  `${Math.round(((userGrowth[userGrowth.length-1]?.cumulative || 0) - userGrowth[0]?.cumulative) / userGrowth[0]?.cumulative * 100)}% growth` 
                  : 'Loading...'}
              </span>
            </div>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Active Users</p>
              <p className="text-2xl font-bold text-text">{stats.activeUsers.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-green-100 rounded-lg">
              <FiUsers className="text-green-600" size={20} />
            </div>
          </div>
          <div className="mt-2">
            <p className="text-xs text-text-light">
              {stats.totalUsers > 0 ? 
                `${Math.round((stats.activeUsers / stats.totalUsers) * 100)}% active rate` 
                : 'No data'}
            </p>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Total Routes</p>
              <p className="text-2xl font-bold text-text">{stats.totalRoutes.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-purple-100 rounded-lg">
              <FiMap className="text-purple-600" size={20} />
            </div>
          </div>
          <div className="mt-2">
            <p className="text-xs text-text-light">
              {routeData.reduce((sum, r) => sum + r.approved, 0)} approved
            </p>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Total Searches</p>
              <p className="text-2xl font-bold text-text">{stats.totalSearches.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-red-100 rounded-lg">
              <FiSearch className="text-red-600" size={20} />
            </div>
          </div>
          <div className="mt-2">
            <p className="text-xs text-text-light">
              {stats.totalUsers > 0 ? 
                `${Math.round(stats.totalSearches / stats.totalUsers)} avg per user` 
                : 'No searches'}
            </p>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Notifications</p>
              <p className="text-2xl font-bold text-text">{stats.notificationsSent.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-yellow-100 rounded-lg">
              <FiBell className="text-yellow-600" size={20} />
            </div>
          </div>
          <div className="mt-2">
            <div className="flex items-center text-green-600 text-xs">
              <FiTrendingUp className="mr-1" />
              <span>
                {notificationData.length > 0 ? 
                  `${Math.round(notificationData.reduce((sum, n) => sum + n.readRate, 0) / notificationData.length)}% read rate` 
                  : 'No data'}
              </span>
            </div>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">User Routes</p>
              <p className="text-2xl font-bold text-text">{stats.userCreatedRoutes.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-indigo-100 rounded-lg">
              <FiNavigation className="text-indigo-600" size={20} />
            </div>
          </div>
          <div className="mt-2">
            <p className="text-xs text-text-light">
              {stats.totalUsers > 0 ? 
                `${Math.round((stats.userCreatedRoutes / stats.totalUsers) * 100)}% create rate` 
                : 'No routes'}
            </p>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Total Stops</p>
              <p className="text-2xl font-bold text-text">{stats.totalStops.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-pink-100 rounded-lg">
              <FiMapPin className="text-pink-600" size={20} />
            </div>
          </div>
        </div>

        <div className="bg-white p-4 rounded-lg shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-xs">Total Revenue</p>
              <p className="text-2xl font-bold text-text">GH₵{stats.totalPayments.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-emerald-100 rounded-lg">
              <FiTrendingUp className="text-emerald-600" size={20} />
            </div>
          </div>
        </div>
      </div>

      {/* Charts Row 1 - Same as before */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* User Growth Chart */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-text">User Growth (Last 12 Months)</h3>
            <FiCalendar className="text-primary" />
          </div>
          <div className="h-80">
            {userGrowth.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={userGrowth}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis />
                  <Tooltip 
                    formatter={(value: number, name: string) => [
                      value.toLocaleString(), 
                      name === 'users' ? 'New Users' : 'Total Users'
                    ]}
                  />
                  <Legend />
                  <Line 
                    type="monotone" 
                    dataKey="users" 
                    stroke="#6b21a8" 
                    strokeWidth={2} 
                    name="New Users"
                    dot={{ r: 4 }}
                  />
                  <Line 
                    type="monotone" 
                    dataKey="cumulative" 
                    stroke="#10B981" 
                    strokeWidth={2} 
                    name="Total Users"
                    strokeDasharray="5 5"
                  />
                </LineChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full">
                <p className="text-text-light">No user growth data available</p>
              </div>
            )}
          </div>
        </div>

        {/* Route Approval Status */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-text">Route Approval Status</h3>
            <FiMap className="text-primary" />
          </div>
          <div className="h-80">
            {routeData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={routeData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="type" />
                  <YAxis />
                  <Tooltip />
                  <Legend />
                  <Bar dataKey="approved" fill="#10B981" name="Approved" />
                  <Bar dataKey="pending" fill="#F59E0B" name="Pending" />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full">
                <p className="text-text-light">No route data available</p>
              </div>
            )}
          </div>
          <div className="mt-4 grid grid-cols-2 gap-4">
            {routeData.map(route => (
              <div key={route.type} className="p-2 bg-gray-50 rounded">
                <p className="text-sm font-medium text-text">{route.type}</p>
                <p className="text-xs text-text-light">
                  {route.approvalRate}% approval rate ({route.approved}/{route.total})
                </p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Charts Row 2 - Same as before */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Notification Performance */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-text">Notification Performance</h3>
            <FiBell className="text-primary" />
          </div>
          <div className="h-64">
            {notificationData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={notificationData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    label={(entry: any) => `${entry.type}: ${entry.count}`}
                    outerRadius={70}
                    fill="#8884d8"
                    dataKey="count"
                    nameKey="type"
                  >
                    {notificationData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip formatter={(value: number, name: string) => [
                    value.toLocaleString(),
                    name === 'count' ? 'Notifications' : 'Read Rate'
                  ]} />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full">
                <p className="text-text-light">No notification data available</p>
              </div>
            )}
          </div>
          <div className="mt-4 space-y-2">
            {notificationData.map(notification => (
              <div key={notification.type} className="flex justify-between items-center">
                <span className="text-sm text-text">{notification.type}</span>
                <div className="flex items-center gap-2">
                  <span className="text-xs text-text-light">
                    {notification.sent} sent, {notification.read} read
                  </span>
                  <span className={`text-xs px-2 py-1 rounded ${
                    notification.readRate > 50 ? 'bg-green-100 text-green-800' :
                    notification.readRate > 20 ? 'bg-yellow-100 text-yellow-800' :
                    'bg-red-100 text-red-800'
                  }`}>
                    {notification.readRate.toFixed(1)}%
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Peak Search Hours */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-text">Peak Search Hours</h3>
            <FiClock className="text-primary" />
          </div>
          <div className="h-64">
            {activeHoursData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={activeHoursData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="formattedHour" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="count" fill="#8b5cf6" name="Searches" />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full">
                <p className="text-text-light">No search data available</p>
              </div>
            )}
          </div>
          <div className="mt-4 grid grid-cols-3 gap-2">
            <div className="text-center">
              <p className="text-sm font-medium text-text">Peak Hour</p>
              <p className="text-lg font-bold text-primary">
                {activeHoursData.length > 0 ? 
                  activeHoursData.reduce((max, hour) => hour.count > max.count ? hour : max, {count: 0}).formattedHour 
                  : 'N/A'}
              </p>
            </div>
            <div className="text-center">
              <p className="text-sm font-medium text-text">Total Searches</p>
              <p className="text-lg font-bold text-text">
                {activeHoursData.reduce((sum, hour) => sum + hour.count, 0).toLocaleString()}
              </p>
            </div>
            <div className="text-center">
              <p className="text-sm font-medium text-text">Avg per Hour</p>
              <p className="text-lg font-bold text-text">
                {activeHoursData.length > 0 ? 
                  Math.round(activeHoursData.reduce((sum, hour) => sum + hour.count, 0) / 24).toLocaleString() 
                  : 0}
              </p>
            </div>
          </div>
        </div>

        {/* User Activity by Hour */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-text">User Activity by Hour</h3>
            <FiUsers className="text-primary" />
          </div>
          <div className="h-64">
            {userDistributionByHour.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={userDistributionByHour}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="formattedHour" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="users" fill="#3B82F6" name="Active Users" />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full">
                <p className="text-text-light">No user activity data available</p>
              </div>
            )}
          </div>
          <div className="mt-4 space-y-2">
            <div className="text-center">
              <p className="text-sm font-medium text-text">Peak Activity Hour</p>
              <p className="text-lg font-bold text-primary">
                {userDistributionByHour.length > 0 ? 
                  userDistributionByHour.reduce((max, hour) => hour.users > max.users ? hour : max, {users: 0}).formattedHour 
                  : 'N/A'}
              </p>
            </div>
            <p className="text-xs text-text-light text-center">
              Based on last seen timestamps of users
            </p>
          </div>
        </div>
      </div>

      {/* Data Lists */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* User Locations by Region */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h3 className="text-lg font-semibold text-text">User Locations by Region</h3>
              <p className="text-sm text-text-light">
                Based on last known locations from user profiles
              </p>
            </div>
            <FiMapPin className="text-primary" />
          </div>
          
          {topRegions.length > 0 ? (
            <>
              <div className="mb-4 p-3 bg-blue-50 rounded-lg">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm text-text-light">Users with location data</p>
                    <p className="text-lg font-bold text-text">
                      {regionSummary.usersWithLocation.toLocaleString()}
                      <span className="text-sm text-text-light ml-2">
                        ({Math.round(regionSummary.locationPercentage)}% of total)
                      </span>
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-text-light">Regions detected</p>
                    <p className="text-lg font-bold text-text">{regionSummary.totalRegions}</p>
                  </div>
                </div>
              </div>

              <div className="space-y-3">
                {topRegions.map((region, index) => {
                  const maxCount = Math.max(...topRegions.map(r => r.count))
                  const percentage = maxCount > 0 ? (region.count / maxCount) * 100 : 0
                  
                  return (
                    <div key={region.name} className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <span className="text-sm font-medium text-text w-6 text-center">
                          #{index + 1}
                        </span>
                        <div>
                          <span className="text-text font-medium">{region.name}</span>
                          <div className="text-xs text-text-light">
                            {Math.round(region.percentage)}% of users with locations
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-4">
                        <div className="w-32 bg-gray-200 rounded-full h-2">
                          <div 
                            className="bg-primary h-2 rounded-full" 
                            style={{ width: `${percentage}%` }}
                          />
                        </div>
                        <div className="text-right min-w-[80px]">
                          <span className="text-text-light font-medium">{region.count.toLocaleString()}</span>
                          <div className="text-xs text-text-light">
                            users
                          </div>
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>
            </>
          ) : (
            <div className="text-center py-8">
              <FiMapPin className="mx-auto text-4xl text-text-light mb-4" />
              <p className="text-text">No user location data available</p>
              <p className="text-sm text-text-light mt-2">
                User locations will appear here once users update their location in the app
              </p>
            </div>
          )}
        </div>

        {/* Popular Searches */}
        <div className="bg-white p-6 rounded-lg shadow">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-text">Popular Routes Searched</h3>
            <FiSearch className="text-primary" />
          </div>
          {popularSearches.length > 0 ? (
            <div className="space-y-3 max-h-96 overflow-y-auto pr-2">
              {popularSearches.map((search, index) => (
                <div key={search.name} className="flex items-center justify-between p-3 hover:bg-gray-50 rounded-lg">
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-medium bg-gray-100 text-gray-800 px-2 py-1 rounded">
                        #{index + 1}
                      </span>
                      <p className="font-medium text-text">{search.name}</p>
                    </div>
                    <p className="text-sm text-text-light">
                      {search.count} search{search.count !== 1 ? 'es' : ''}
                    </p>
                  </div>
                  <div className="flex flex-col items-end">
                    <span className={`text-xs px-2 py-1 rounded-full ${
                      search.popularity === 'High' ? 'bg-red-100 text-red-800' :
                      search.popularity === 'Medium' ? 'bg-yellow-100 text-yellow-800' :
                      'bg-green-100 text-green-800'
                    }`}>
                      {search.popularity}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-8">
              <FiSearch className="mx-auto text-4xl text-text-light mb-4" />
              <p className="text-text">No search data available</p>
              <p className="text-sm text-text-light mt-2">
                Search data will appear here once users start searching for routes
              </p>
            </div>
          )}
        </div>
      </div>

      {/* Refresh Button */}
      <div className="bg-white p-6 rounded-lg shadow">
        <div className="flex justify-between items-center">
          <div>
            <h3 className="text-lg font-semibold text-text">Analytics Data</h3>
            <p className="text-sm text-text-light">Last updated: {new Date().toLocaleTimeString()}</p>
          </div>
          <button
            onClick={fetchAnalyticsData}
            className="px-6 py-3 bg-primary text-white rounded-lg hover:bg-primary-dark transition-colors flex items-center gap-2"
          >
            <FiTrendingUp />
            Refresh Analytics
          </button>
        </div>
      </div>
    </div>
  )
}